    19→std::string StringUtils::to_lower(const std::string& str)
    20→{
    21→    std::string ret(str);
    22→    for (size_t i = 0; i < ret.size(); ++i) {
    23→        if (Ascii::is_upper(ret[i])) {
    24→            ret[i] = Ascii::to_lower(ret[i]); 
    25→        }
    26→    }
    27→    return ret;
    28→}
    29→
    30→std::string StringUtils::to_upper(const std::string& str)
    31→{
    32→    std::string ret(str);
    33→    for (size_t i = 0; i < ret.size(); ++i) {
    34→        if (Ascii::is_lower(ret[i])) {
    35→            ret[i] = Ascii::to_upper(ret[i]); 
    36→        }
    37→    }
    38→    return ret;
    39→}
