    41→bool StringUtils::end_with(const std::string& str, const std::string& match)
    42→{
    43→    return str.size() >= match.size()
    44→        && str.rfind(match) + match.size() == str.size(); 
    45→}
    46→
    47→bool StringUtils::begin_with(const std::string& str, const std::string& match)
    48→{
    49→    return str.size() >= match.size()
    50→        && str.substr(0, match.size()) == match;
    51→}
