    53→std::string StringUtils::trim(const std::string& str)
    54→{
    55→    size_t start_pos = 0;
    56→    size_t end_pos = str.length();
    57→    while (start_pos != end_pos && Ascii::is_space(str[start_pos]))
    58→        start_pos++;
    59→    if (start_pos == end_pos) {
    60→        return "";
    61→    }
    62→    end_pos--;
    63→    while (Ascii::is_space(str[end_pos])) // end_pos always >= 0
    64→        end_pos--;
    65→    return str.substr(start_pos, end_pos - start_pos + 1);
    66→}
    67→
    68→void StringUtils::split(const std::string& str, const std::string& delim,
    69→        std::vector<std::string>* substr_list)
    70→{
    71→    substr_list->clear();
    72→    if (str.empty() || delim.empty()) {
    73→        substr_list->push_back(str);
    74→        return;
    75→    }
    76→    std::string::size_type start = 0;
    77→    while (true) {
    78→        std::string::size_type pos = str.find(delim, start);
    79→        if (pos == start) {
    80→            substr_list->push_back(std::string());
    81→            start += delim.length();
    82→            continue;
    83→        }
    84→        else if (pos == std::string::npos) {
    85→            substr_list->push_back(str.substr(start));
    86→            break;
    87→        }
    88→        else {
    89→            substr_list->push_back(str.substr(start, pos - start));
    90→            start = pos + delim.length();
    91→        }
    92→    }
    93→}
