    95→std::string StringUtils::join(const std::vector<std::string>& components,
    96→        const std::string& delim)
    97→{
    98→    std::ostringstream oss;
    99→    for (std::vector<std::string>::const_iterator it = components.begin();
   100→         it != components.end(); ++it)
   101→    {
   102→        if (it != components.begin())
   103→            oss << delim;
   104→        oss << *it;
   105→    }
   106→    return oss.str();
   107→}
   108→
   109→std::string StringUtils::replace(const std::string& str,
   110→        const std::string& oldsub, const std::string& newsub)
   111→{
   112→    if (oldsub.empty()) return str;
   113→    std::string res;
   114→    std::string::size_type pos = str.find(oldsub);
   115→    if (pos == std::string::npos) {
   116→        return str;
   117→    }
   118→    else {
   119→        res.append(str.data(), pos);
   120→        res.append(newsub.data(), newsub.size());
   121→        res.append(str.data() + pos + oldsub.size(), str.size() - pos - oldsub.size());
   122→    }
   123→    return res;
   124→}
   125→
   126→std::string StringUtils::replace_all(const std::string& str,
   127→        const std::string& oldsub, const std::string& newsub)
   128→{
   129→    if (oldsub.empty()) return str;
   130→    std::string res;
   131→    std::string::size_type start_pos = 0;
   132→    std::string::size_type pos;
   133→    do {
   134→        pos = str.find(oldsub, start_pos);
   135→        if (pos == std::string::npos) {
   136→            break;
   137→        }
   138→        res.append(str.data() + start_pos, pos - start_pos);
   139→        res.append(newsub.data(), newsub.size());
   140→        start_pos = pos + oldsub.size();
   141→    } while (true);
   142→    res.append(str.data() + start_pos, str.size() - start_pos);
   143→    return res;
   144→}
