   153→////////////// c_escape ///////////////////////////////
   154→#define IS_OCTAL_DIGIT(c) (((c) >= '0') && ((c) <= '7'))
   155→
   156→inline bool isxdigit(char c) {
   157→    return ('0' <= c && c <= '9') || ('a' <= c && c <= 'f') || ('A' <= c && c <= 'F');
   158→}
   159→
   160→inline bool isprint(char c) {
   161→    return c >= 0x20 && c <= 0x7E;
   162→}
   163→
   164→static int c_escape_string_internal(const char* src, int src_len, char* dest, int dest_len) {
   165→    int used = 0;
   166→    const char* src_end = src + src_len;
   167→    for (; src < src_end; src++) {
   168→        // at least two chars needed.
   169→        if (dest_len - used < 2) {
   170→            return -1;
   171→        }
   172→        unsigned char c = *src;
   173→        switch (c) {
   174→            case '\n': dest[used++] = '\\'; dest[used++] = 'n';  break;
   175→            case '\r': dest[used++] = '\\'; dest[used++] = 'r';  break;
   176→            case '\t': dest[used++] = '\\'; dest[used++] = 't';  break;
   177→            case '\"': dest[used++] = '\\'; dest[used++] = '\"'; break;
   178→            case '\'': dest[used++] = '\\'; dest[used++] = '\''; break;
   179→            case '\\': dest[used++] = '\\'; dest[used++] = '\\'; break;
   180→            default:
   181→                if (c == '\0' && (src + 1 == src_end || !IS_OCTAL_DIGIT(src[1]))) {
   182→                    dest[used++] = '\\';
   183→                    dest[used++] = '0';
   184→                }
   185→                else if (c < ' ' || c > '~') {
   186→                    if (dest_len - used < 4) {
   187→                        return -1;
   188→                    }
   189→                    sprintf(dest + used, "\\%03o", c);
   190→                    used += 4;
   191→                }
   192→                else {
   193→                    dest[used++] = c;
   194→                }
   195→        }
   196→    }
   197→    if (dest_len - used < 1)
   198→        return -1;
   199→    dest[used] = '\0';
   200→    return used;
   201→}
   202→
   203→std::string StringUtils::c_escape_string(const char* src, int src_len)
   204→{
   205→    int dest_length = src_len * 4 + 1; // Maximum space needed
   206→    sofa::pbrpc::scoped_array<char> dest(new char[dest_length]);
   207→    int len = c_escape_string_internal(src, src_len, dest.get(), dest_length);
   208→    assert(len >= 0);
   209→    return std::string(dest.get(), len);
   210→}
