   212→////////////// c_unescape ///////////////////////////////
   213→////// Come from google/protobuf/stubs/strutils.cc //////
   214→inline int hex_digit_to_int(char c) {
   215→    /* Assume ASCII. */
   216→    assert('0' == 0x30 && 'A' == 0x41 && 'a' == 0x61);
   217→    assert(isxdigit(c));
   218→    int x = static_cast<unsigned char>(c);
   219→    if (x > '9') {
   220→        x += 9;
   221→    }
   222→    return x & 0xf;
   223→}
   224→
   225→static int unescape_c_escape_sequences(const char* source, char* dest)
   226→{
   227→    char* d = dest;
   228→    const char* p = source;
   229→
   230→    // Small optimization for case where source = dest and there's no escaping
   231→    while ( p == d && *p != '\0' && *p != '\\' ) {
   232→        p++;
   233→        d++;
   234→    }
   235→
   236→    while (*p != '\0') {
   237→        if (*p != '\\') {
   238→            *d++ = *p++;
   239→        } else {
   240→            switch ( *++p ) {                    // skip past the '\\'
   241→                case '\0':
   242→                    throw std::runtime_error("bad c-escape string");
   243→                case 'a':  *d++ = '\a';  break;
   244→                case 'b':  *d++ = '\b';  break;
   245→                case 'f':  *d++ = '\f';  break;
   246→                case 'n':  *d++ = '\n';  break;
   247→                case 'r':  *d++ = '\r';  break;
   248→                case 't':  *d++ = '\t';  break;
   249→                case 'v':  *d++ = '\v';  break;
   250→                case '\\': *d++ = '\\';  break;
   251→                case '?':  *d++ = '\?';  break;    // \?  Who knew?
   252→                case '\'': *d++ = '\'';  break;
   253→                case '"':  *d++ = '\"';  break;
   254→                case '0': case '1': case '2': case '3':  // octal digit: 1 to 3 digits
   255→                case '4': case '5': case '6': case '7': {
   256→                    char ch = *p - '0';
   257→                    if ( IS_OCTAL_DIGIT(p[1]) ) {
   258→                        ch = ch * 8 + *++p - '0';
   259→                    }
   260→                    if ( IS_OCTAL_DIGIT(p[1]) ) {      // safe (and easy) to do this twice
   261→                        ch = ch * 8 + *++p - '0';      // now points at last digit
   262→                    }
   263→                    *d++ = ch;
   264→                    break;
   265→                }
   266→                case 'x': case 'X': {
   267→                    if (!isxdigit(p[1])) {
   268→                        if (p[1] == '\0') {
   269→                            throw std::runtime_error("bad c-escape string");
   270→                        }
   271→                        else {
   272→                            throw std::runtime_error("bad c-escape string");
   273→                        }
   274→                        break;
   275→                    }
   276→                    unsigned int ch = 0;
   277→                    while (isxdigit(p[1])) { // arbitrarily many hex digits
   278→                        ch = (ch << 4) + hex_digit_to_int(*++p);
   279→                    }
   280→                    if (ch > 0xFF) {
   281→                        throw std::runtime_error("bad c-escape string");
   282→                    }
   283→                    *d++ = ch;
   284→                    break;
   285→                }
   286→                case 'u': case 'U': {
   287→                    // TODO: support \u and \U ?
   288→                    throw std::runtime_error("bad c-escape string");
   289→                }
   290→                default:
   291→                    throw std::runtime_error("bad c-escape string");
   292→            }
   293→            p++; // read past letter we escaped
   294→        }
   295→    }
   296→    *d = '\0';
   297→    return d - dest;
   298→}
   299→
   300→std::string StringUtils::unescape_c_escape_string(const std::string& src)
   301→{
   302→    sofa::pbrpc::scoped_array<char> unescaped(new char[src.size() + 1]);
   303→    int len = unescape_c_escape_sequences(src.c_str(), unescaped.get());
   304→    return std::string(unescaped.get(), len);
   305→}
