   307→////////////// xml_escape ///////////////////////////////
   308→void StringUtils::xml_escape_string(std::ostream& os, const char* src, int src_len)
   309→{
   310→    for (int i = 0; i < src_len; ++i) {
   311→        char ch = *(src + i);
   312→        switch (ch) {
   313→            case '&': os << "&amp;"; break;
   314→            case '\'': os << "&apos;"; break;
   315→            case '"': os << "&quot;"; break;
   316→            case '<': os << "&lt;"; break;
   317→            case '>': os << "&gt;"; break;
   318→            default: os << ch;
   319→        }
   320→    }
   321→}
   322→
   323→std::string StringUtils::xml_escape_string(const char* src, int src_len)
   324→{
   325→    std::stringstream os;
   326→    xml_escape_string(os, src, src_len);
   327→    return os.str();
   328→}
   329→
   330→////////////// json_escape ///////////////////////////////
   331→void StringUtils::json_escape_string(std::ostream& os, const char* src, int src_len)
   332→{
   333→    for (int i = 0; i < src_len; ++i) {
   334→        char c = *(src + i);
   335→        switch (c)
   336→        {
   337→            case '"': os << "\\\""; break;
   338→            case '\\': os  << "\\\\"; break;
   339→            case '/': os << "\\/"; break;
   340→            case '\b': os << "\\b"; break;
   341→            case '\f': os << "\\f"; break;
   342→            case '\n': os << "\\n"; break;
   343→            case '\r': os << "\\r"; break;
   344→            case '\t': os << "\\t"; break;
   345→            case '\0': os << "\\u0000"; break;
   346→            default: os << c;
   347→        }
   348→    }
   349→}
   350→
   351→std::string StringUtils::json_escape_string(const char* src, int src_len)
   352→{
   353→    std::stringstream os;
   354→    json_escape_string(os, src, src_len);
   355→    return os.str();
