   378→
   379→// Characters defined by RFC 3986.
   380→const unsigned char URL_CHR_TABLE[256] =
   381→{
   382→    U,  U,  U,  U,   U,  U,  U,  U,   /* NUL SOH STX ETX  EOT ENQ ACK BEL */
