   397→    0,  0,  0,  U,   U,  U,  0,  U,   /* x   y   z   {    |   }   ~   DEL */
   398→
   399→    U, U, U, U,  U, U, U, U,  U, U, U, U,  U, U, U, U,
   400→    U, U, U, U,  U, U, U, U,  U, U, U, U,  U, U, U, U,
   401→    U, U, U, U,  U, U, U, U,  U, U, U, U,  U, U, U, U,
   402→    U, U, U, U,  U, U, U, U,  U, U, U, U,  U, U, U, U,
   403→
   404→    U, U, U, U,  U, U, U, U,  U, U, U, U,  U, U, U, U,
   405→    U, U, U, U,  U, U, U, U,  U, U, U, U,  U, U, U, U,
   406→    U, U, U, U,  U, U, U, U,  U, U, U, U,  U, U, U, U,
   407→    U, U, U, U,  U, U, U, U,  U, U, U, U,  U, U, U, U,
   408→};
   409→
   410→#undef RU
   411→#undef U
   412→#undef R
   413→
   414→void StringUtils::encode_url(std::ostream& os, const std::string& str, int flag)
   415→{
   416→    size_t len = str.size();
   417→    for (size_t pos = 0; pos < len; pos++)
   418→    {
   419→        unsigned char ch = str[pos];
   420→        if ('%' == ch)
   421→        {
   422→            if (((pos + 2) < len) && isxdigit(str[pos + 1]) && isxdigit(str[pos + 2]))
   423→            {
   424→                os << ch;
   425→            }
   426→            else
   427→            {
   428→                os << '%' << XNUM_TO_DIGIT(ch >> 4) << XNUM_TO_DIGIT(ch & 0xf);
   429→            }
   430→        }
   431→        else if (URL_UNSAFE_CHAR (ch))
   432→        {
   433→            if ((!(flag & E_ENCODE_RESERVED_CHAR) && URL_RESERVED_CHAR (ch))
   434→                    || ((flag & E_NOT_ENCODE_HIGH_CHAR) && (ch > 127)))
   435→            {
   436→                os << ch;
